'use strict';

var _index = require('./index');

describe('packets', function () {
  describe('pubrel', function () {
    describe('encode', function () {
      test('normal', function () {
        expect((0, _index.encode)({
          type: 'pubrel',
          id: 1337
        })).toEqual([
        // fixedHeader
        0x62, // packetType + flags
        2, // remainingLength
        // variableHeader
        5, // id MSB
        57] // id LSB
        );
      });
    });

    describe('decode', function () {
      test('too short', function () {
        expect((0, _index.decode)(Uint8Array.from([0x62]))).toBe(null);
        expect((0, _index.decode)(Uint8Array.from([0x62, 2]))).toBe(null);
        expect((0, _index.decode)(Uint8Array.from([0x62, 2, 5]))).toBe(null);
      });

      test('normal', function () {
        expect((0, _index.decode)(Uint8Array.from([
        // fixedHeader
        0x62, // packetType + flags
        2, // remainingLength
        // variableHeader
        5, // id MSB
        57] // id LSB
        ))).toEqual({
          type: 'pubrel',
          id: 1337
        });
      });
    });
  });
});

/* eslint-env jest */